+#[derive(Debug, Deserialize)]
+struct MatrixCaseEnvelope {
+    kind: String,
+    #[serde(default)]
+    run: Option<DifferentialExecution>,
+    #[serde(default)]
+    error: Option<String>,
+}
+
+#[derive(Debug, Deserialize)]
+struct DifferentialExecution {
+    host_output: String,
+    impl_output: String,
+    host_parity: bool,
+}
